import java.util.Arrays;

public class ArrayBasicOps {
    public static void main(String[] args) {
        // Declaration and Initialization
        int[] numbers = new int[5];  // Size 5, all zeros
        int[] values = {10, 20, 30, 40, 50};  // Initialize with values

        // Assign values to first array
        numbers[0] = 100;
        numbers[1] = 200;

        // Using length property
        System.out.println("Length: " + values.length);

        // Traditional for loop
        for (int i = 0; i < values.length; i++) {
            System.out.println("Index " + i + ": " + values[i]);
        }

        // Enhanced for loop
        for (int num : numbers) {
            System.out.println("Value: " + num);
        }

        // Using Arrays class
        System.out.println(Arrays.toString(values));

        // Fill array
        Arrays.fill(numbers, 50);
    }
}

public class SearchAlgorithms {

    // Linear Search - O(n)
    public static int linearSearch(int[] arr, int target) {
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) {
                return i;  // Found, return index
            }
        }
        return -1;  // Not found
    }

    // Binary Search - O(log n) - requires sorted array
    public static int binarySearch(int[] arr, int target) {
        int left = 0;
        int right = arr.length - 1;

        while (left <= right) {
            int mid = left + (right - left) / 2;

            if (arr[mid] == target) {
                return mid;
            } else if (arr[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return -1;  // Not found
    }

    public static void main(String[] args) {
        int[] arr = {2, 5, 8, 12, 16, 23, 38, 56, 72, 91};
        int target = 23;

        System.out.println("Linear Search: " + linearSearch(arr, target));
        System.out.println("Binary Search: " + binarySearch(arr, target));
    }
}

public class BubbleSort {

    public static void bubbleSort(int[] arr) {
        int n = arr.length;
        boolean swapped;

        for (int i = 0; i < n - 1; i++) {
            swapped = false;

            // Last i elements are already sorted
            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j] > arr[j + 1]) {
                    // Swap elements
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                    swapped = true;
                }
            }

            // If no swapping occurred, array is sorted
            if (!swapped) {
                break;
            }
        }
    }

    public static void main(String[] args) {
        int[] arr = {64, 34, 25, 12, 22, 11, 90};

        System.out.print("Original: ");
        for (int num : arr) System.out.print(num + " ");

        bubbleSort(arr);

        System.out.print("\nSorted: ");
        for (int num : arr) System.out.print(num + " ");
    }
}

public class TwoDArrayDemo {

    public static void main(String[] args) {
        // Regular 2D array - 3 rows, 4 columns
        int[][] matrix = new int[3][4];

        // Initialize with values
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 4; j++) {
                matrix[i][j] = i * 4 + j + 1;
            }
        }

        // Print matrix
        System.out.println("Regular 2D Array:");
        for (int[] row : matrix) {
            for (int val : row) {
                System.out.print(val + "\t");
            }
            System.out.println();
        }

        // Jagged array - different column sizes
        int[][] jagged = new int[3][];
        jagged[0] = new int[2];  // 2 columns
        jagged[1] = new int[4];  // 4 columns
        jagged[2] = new int[3];  // 3 columns

        // Initialize jagged array
        for (int i = 0; i < jagged.length; i++) {
            for (int j = 0; j < jagged[i].length; j++) {
                jagged[i][j] = i + j;
            }
        }

        // Print jagged array
        System.out.println("\nJagged Array:");
        for (int[] row : jagged) {
            for (int val : row) {
                System.out.print(val + " ");
            }
            System.out.println();
        }
    }
}
